const idx = $itemIndex ?? 0;

// безопасно достаём items из других нод (если ноды нет/нет pairing — будет [])
const getItemsSafe = (nodeName) => {
  try {
    const arr = $items(nodeName);
    return Array.isArray(arr) ? arr : [];
  } catch (e) {
    return [];
  }
};

const webhookItems = getItemsSafe("Webhook");

// body: сначала текущий idx, потом 0, потом вход $json
const body =
  webhookItems[idx]?.json?.body ??
  webhookItems[0]?.json?.body ??
  $json.body ??
  {};

// ---------- helpers ----------
const isNil = (v) => v === null || v === undefined;
const clean = (v) => (typeof v === "string" ? v.trim() : v);

const val = (v) => {
  v = clean(v);
  if (isNil(v) || v === "" || v === "null" || v === "undefined") return "---";
  return String(v);
};

const safeArr = (a) => (Array.isArray(a) ? a : []);
const esc = (s) =>
  String(s)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");

const numFormat = (x) => {
  if (isNil(x)) return "---";
  if (typeof x === "string") {
    const s = x.replace(/\s+/g, "").replace(/,/g, ".");
    if (s === "" || s === "-" || s === "null" || s === "undefined") return "---";
    const n = Number(s);
    if (!Number.isFinite(n)) return val(x);
    x = n;
  }
  if (typeof x !== "number" || !Number.isFinite(x)) return val(x);

  const fixed = (Math.round(x * 100) / 100).toString();
  const [intPart, decPart] = fixed.split(".");
  const grouped = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, " ");
  return decPart ? `${grouped}.${decPart.padEnd(2, "0")}` : `${grouped}.00`;
};

const joinAddress = (region, district, street) => {
  const r = val(region);
  const d = val(district);
  const s = val(street);
  return [r, d, s].join(", ");
};

const bankAccFormat = (acc) => {
  const raw = val(acc);
  if (raw === "---") return "---";
  const a = raw.replace(/\s+/g, "");
  const m = a.match(/^(.{5})(.{3})(.{1})(.{8})(.*)$/);
  return m ? `${m[1]} ${m[2]} ${m[3]} ${m[4]} ${m[5]}` : raw;
};

const fullName = (p) => {
  if (!p) return "---";
  const parts = [p.lastName, p.firstName, p.middleName]
    .filter(Boolean)
    .map(val)
    .filter((v) => v !== "---");
  return parts.length ? parts.join(" ") : "---";
};

const findRow = (rows, rowNo, field) => {
  const r = safeArr(rows).find((x) => String(x?.row_no ?? "") === String(rowNo));
  if (!r) return "---";
  const v = r[field];
  if (isNil(v)) return "---";
  return numFormat(v);
};

